2545	test "expect State.add auto-fills missing horn in valid cases" {
2546	    // Arrange: starting pair shapes covering both auto-fill targets and all
2547	    // case combinations. `receiving_offset` marks which vowel in the pair
2548	    // gains horn (0 = first, 1 = second).
2549	    const PairCase = struct {
2550	        first_base: u8,
2551	        first_diacritic: Diacritic,
2552	        second_base: u8,
2553	        second_diacritic: Diacritic,
2554	        receiving_offset: u8,
2555	    };
2556	    const pair_cases = [_]PairCase{
2557	        // uơ pattern: first vowel is missing horn.
2558	        .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
2559	        .{ .first_base = 'u', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
2560	        .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'o', .second_diacritic = .horn, .receiving_offset = 0 },
2561	        .{ .first_base = 'U', .first_diacritic = .empty, .second_base = 'O', .second_diacritic = .horn, .receiving_offset = 0 },
2562	        // ưo pattern: second vowel is missing horn.
2563	        .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
2564	        .{ .first_base = 'u', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
2565	        .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'o', .second_diacritic = .empty, .receiving_offset = 1 },
2566	        .{ .first_base = 'U', .first_diacritic = .horn, .second_base = 'O', .second_diacritic = .empty, .receiving_offset = 1 },
2567	    };
2568	
2569	    const triggers = [_]u8{ 'C', 'c', 'I', 'i', 'M', 'm', 'N', 'n', 'P', 'p', 'T', 't', 'U', 'u' };
2570	
2571	    const tones = [_]Tone{ .level, .rising, .falling, .dipping_rising, .rising_glottalized, .falling_glottalized };
2572	
2573	    // Linguistically valid one-tone syllables: a tone may sit on either vowel.
2574	    // Sweep both positions while the other vowel stays at .level. We do not
2575	    // fabricate double-toned syllables that the spec would not consider valid.
2576	    const tone_positions = [_]u8{ 0, 1 };
2577	
2578	    // Cover both pair-at-start (no prefix) and pair-after-consonant variants
2579	    // to prove the rule looks at the last two spans regardless of buffer_length.
2580	    const prefix_lengths = [_]u8{ 0, 1 };
2581	
2582	    for (pair_cases) |pc| {
2583	        for (triggers) |trig| {
2584	            for (tones) |tn| {
2585	                for (tone_positions) |tpos| {
2586	                    for (prefix_lengths) |plen| {
2587	                        var state: State = undefined;
2588	                        state.init();
2589	
2590	                        // Optional 'b' prefix to place the pair at index 1..2.
2591	                        if (plen == 1) {
2592	                            state.buffer_effective[0] = Span.init('b');
2593	                        }
2594	
2595	                        const first_tone: Tone = if (tpos == 0) tn else .level;
2596	                        const second_tone: Tone = if (tpos == 1) tn else .level;
2597	
2598	                        state.buffer_effective[plen] = Span.init_diacritic_tone(pc.first_base, pc.first_diacritic, first_tone);
2599	                        state.buffer_effective[plen + 1] = Span.init_diacritic_tone(pc.second_base, pc.second_diacritic, second_tone);
2600	                        state.buffer_length = plen + 2;
2601	
2602	                        // Act
2603	                        state.add(trig);
2604	
2605	                        // Assert
2606	                        const receiving_index = plen + pc.receiving_offset;
2607	                        try expectEqual(plen + 3, state.buffer_length);
2608	                        try expectEqual(receiving_index, state.buffer_modification_index);
2609	                        try expectEqual(null, state.literal_index);
2610	
2611	                        // Prefix, when present, must be unchanged.
2612	                        if (plen == 1) {
2613	                            const sp_prefix = state.buffer_effective[0];
2614	                            try expectEqual(@as(u8, 'b'), sp_prefix.base);
2615	                            try expectEqual(.empty, sp_prefix.diacritic);
2616	                            try expectEqual(.level, sp_prefix.tone);
2617	                        }
2618	
2619	                        // Both vowel spans must end with horn; case and tone preserved.
2620	                        const sp_first = state.buffer_effective[plen];
2621	                        try expectEqual(pc.first_base, sp_first.base);
2622	                        try expectEqual(.horn, sp_first.diacritic);
2623	                        try expectEqual(first_tone, sp_first.tone);
2624	
2625	                        const sp_second = state.buffer_effective[plen + 1];
2626	                        try expectEqual(pc.second_base, sp_second.base);
2627	                        try expectEqual(.horn, sp_second.diacritic);
2628	                        try expectEqual(second_tone, sp_second.tone);
2629	
2630	                        // The trigger character is appended literally.
2631	                        const sp_new = state.buffer_effective[plen + 2];
2632	                        try expectEqual(trig, sp_new.base);
2633	                        try expectEqual(.empty, sp_new.diacritic);
2634	                        try expectEqual(.level, sp_new.tone);
2635	                    }
2636	                }
2637	            }
2638	        }
2639	    }
2640	}
